import type { Metadata } from "next";
import { Plus_Jakarta_Sans, JetBrains_Mono } from "next/font/google";
import "./globals.css";
import { WorkspaceLayoutProvider } from "@/components/workspace-layout-provider";

const plusJakartaSans = Plus_Jakarta_Sans({
  subsets: ["latin"],
  variable: "--font-sans",
  weight: ["300", "400", "500", "600", "700", "800"],
  display: "swap",
});

const jetBrainsMono = JetBrains_Mono({
  subsets: ["latin"],
  variable: "--font-mono",
  display: "swap",
});

export const metadata: Metadata = {
  title: "Varguard Metadata Hub",
  description: "Platform metadata governance untuk mengelola metadata statistik, dataset, lineage, dan MDM.",
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="id" className={`${plusJakartaSans.variable} ${jetBrainsMono.variable} h-full antialiased`} suppressHydrationWarning>
      <head>
        <script
          dangerouslySetInnerHTML={{
            __html: `
              (function () {
                var root = document.documentElement;
                var savedTheme = localStorage.getItem("vg-theme");
                var prefersDark = window.matchMedia("(prefers-color-scheme: dark)").matches;
                var isDark = savedTheme ? savedTheme === "dark" : prefersDark;
                root.classList.toggle("dark", isDark);
                root.classList.toggle("light", !isDark);
              })();
            `,
          }}
        />
      </head>
      <body className="min-h-full flex flex-col font-sans">
        <WorkspaceLayoutProvider>{children}</WorkspaceLayoutProvider>
      </body>
    </html>
  );
}

