export function WorkspaceLayoutProvider({ children }: { children: React.ReactNode }) {
  const [tenantId, setTenantId] = useState("tenant-spbe");
  const [isDarkMode, setIsDarkMode] = useState(true);
  const [sidebarWidth, setSidebarWidth] = useState(240);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);

  // Mapping tenant codes to names
  const tenantName = tenantId === "tenant-spbe" ? "SPBE Pemerintah RI" : "Kementerian Keuangan";
  const tenantDomainLabel = tenantId === "tenant-spbe" ? "tenant-spbe" : "tenant-kemenkeu";

  React.useEffect(() => {
    const root = document.documentElement;
    const savedTheme = localStorage.getItem("vg-theme");
    const nextIsDark = savedTheme ? savedTheme === "dark" : root.classList.contains("dark");
    setIsDarkMode(nextIsDark);
    root.classList.toggle("dark", nextIsDark);
    root.classList.toggle("light", !nextIsDark);

    // Load sidebar preferences
    const savedWidth = localStorage.getItem("vg-sidebar-width");
    if (savedWidth) {
      setSidebarWidth(parseInt(savedWidth, 10));
    }
    const savedCollapsed = localStorage.getItem("vg-sidebar-collapsed");
    if (savedCollapsed) {
      setIsSidebarCollapsed(savedCollapsed === "true");
    }
  }, []);

  const handleThemeToggle = () => {
    const nextIsDark = !isDarkMode;
    setIsDarkMode(nextIsDark);
    const root = document.documentElement;
    root.classList.toggle("dark", nextIsDark);
    root.classList.toggle("light", !nextIsDark);
    localStorage.setItem("vg-theme", nextIsDark ? "dark" : "light");
  };

  return (
    <TenantContext.Provider value={{ tenantId, setTenantId, tenantName }}>
      <div
        className="flex h-screen w-screen flex-col overflow-hidden bg-background font-sans text-foreground"
        style={{
          "--sidebar-width": isSidebarCollapsed ? "60px" : `${sidebarWidth}px`,
        } as React.CSSProperties}
      >
        {/* Header */}
        <header className="z-10 flex h-14 shrink-0 select-none items-center justify-between bg-panel px-4 lg:px-5 xl:px-6 2xl:px-8">

