"use client";

import * as React from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import {
  LayoutDashboard,
  Database,
  LineChart,
  TableProperties,
  GitBranch,
  Network,
  ShieldCheck,
  GitMerge,
  Settings,
  Grid2X2,
  Workflow,
  ChevronLeft,
  ChevronRight
} from "lucide-react";
import { cn } from "@/shared/design-system/utils/cn";

export interface NavSidebarProps {
  isCollapsed: boolean;
  setIsCollapsed: (collapsed: boolean) => void;
  width: number;
  setWidth: (width: number) => void;
}

export function NavSidebar({ isCollapsed, setIsCollapsed, width, setWidth }: NavSidebarProps) {
  const pathname = usePathname();

  const mainMenuItem = { name: "Dashboard", href: "/dashboard", icon: LayoutDashboard };
  const menuGroups = [
    {
      label: "Metadata Authoring",
      items: [
        { name: "Dataset Registry", href: "/datasets", icon: Database },
        { name: "Variable Registry", href: "/variables", icon: TableProperties },
        { name: "Classifications", href: "/classifications", icon: Grid2X2 },
        { name: "Indicator Registry", href: "/indicators", icon: LineChart }
      ]
    },
    {
      label: "Data Stewardship",
      items: [
        { name: "Lightweight MDM", href: "/mdm", icon: GitMerge },
        { name: "Metadata Quality", href: "/quality", icon: ShieldCheck },
        { name: "Lineage Graph", href: "/lineage", icon: GitBranch }
      ]
    },
    {
      label: "Control & Compliance",
      items: [{ name: "Governance Approval", href: "/governance", icon: Workflow }]
    },
    {
      label: "Platform & Admin",
      items: [
        { name: "Integrations & API", href: "/integrations", icon: Network },
        { name: "System Settings", href: "/settings", icon: Settings }
      ]
    }
  ];

  const handleMouseDown = (e: React.MouseEvent) => {
    e.preventDefault();
    if (isCollapsed) return;

    const startX = e.clientX;
    const startWidth = width;

    const handleMouseMove = (moveEvent: MouseEvent) => {
      const currentWidth = startWidth + (moveEvent.clientX - startX);
      if (currentWidth >= 180 && currentWidth <= 400) {
        setWidth(currentWidth);
        localStorage.setItem("vg-sidebar-width", String(currentWidth));
      }
    };

    const handleMouseUp = () => {
      document.removeEventListener("mousemove", handleMouseMove);
      document.removeEventListener("mouseup", handleMouseUp);
    };

    document.addEventListener("mousemove", handleMouseMove);
    document.addEventListener("mouseup", handleMouseUp);
  };

  const renderNavItem = (item: { name: string; href: string; icon: React.ComponentType<{ className?: string }> }) => {
    const isActive = pathname.startsWith(item.href);
    const Icon = item.icon;
    return (
      <Link
        key={item.href}
        href={item.href}
        className={cn(
          "group flex items-center gap-3 rounded-control px-3 py-2.5 text-xs font-medium transition-all",
          isActive
            ? "bg-primary font-semibold text-primary-foreground shadow-sm shadow-primary/10"
            : "text-muted-foreground hover:bg-muted hover:text-foreground",
          isCollapsed && "justify-center px-2"
        )}
        title={isCollapsed ? item.name : undefined}
      >
        <Icon
          className={cn(
            "h-4 w-4 transition-transform group-hover:scale-105 shrink-0",
            isActive ? "text-primary-foreground" : "text-muted-foreground group-hover:text-foreground"
          )}
        />
        {!isCollapsed && <span className="truncate">{item.name}</span>}
      </Link>
    );
  };

  return (
    <aside className="shell-sidebar-width relative flex h-full shrink-0 select-none flex-col bg-panel border-r border-border text-foreground">
      {/* Navigation Menu */}
      <nav className="flex-1 space-y-4 overflow-y-auto px-3 py-4">
        <div className="space-y-1">
          {renderNavItem(mainMenuItem)}
        </div>

        {menuGroups.map((group) => (
          <div key={group.label} className="space-y-1">
            {!isCollapsed ? (
              <p className="px-3 pb-1 text-[10px] font-semibold uppercase tracking-wider text-muted-foreground truncate">
                {group.label}
              </p>
            ) : (
              <div className="h-px bg-border my-2 mx-1" />
            )}
            {group.items.map((item) => renderNavItem(item))}
          </div>
        ))}
      </nav>

      {/* Resize Handle */}
      {!isCollapsed && (
        <div
          onMouseDown={handleMouseDown}
          className="absolute right-0 top-0 bottom-0 w-1 cursor-col-resize hover:bg-primary/50 active:bg-primary transition-colors z-20"
        />
      )}

      {/* Collapse Toggle Footer */}
      <div className="mt-auto border-t border-border p-2 flex justify-end">
        <button
          onClick={() => {
            const nextCollapsed = !isCollapsed;
            setIsCollapsed(nextCollapsed);
            localStorage.setItem("vg-sidebar-collapsed", String(nextCollapsed));
          }}
          className="p-1.5 rounded-control text-muted-foreground hover:bg-muted hover:text-foreground transition-all ml-auto flex items-center justify-center animate-fade-in"
          title={isCollapsed ? "Expand Sidebar" : "Collapse Sidebar"}
        >
          {isCollapsed ? <ChevronRight className="w-4 h-4" /> : <ChevronLeft className="w-4 h-4" />}
        </button>
      </div>
    </aside>
  );
}

