"use client";

import React, { createContext, useContext, useState } from "react";
import { NavSidebar } from "./nav-sidebar";
import { Search, Bell, HelpCircle, ChevronsUpDown, UserRound, Building2, Moon, Sun, Menu } from "lucide-react";

// Simple Tenant Context
interface TenantContextType {
  tenantId: string;
  setTenantId: (id: string) => void;
  tenantName: string;
}

const TenantContext = createContext<TenantContextType>({
  tenantId: "tenant-spbe",
  setTenantId: () => {},
  tenantName: "SPBE Pemerintah RI"
});

export const useTenant = () => useContext(TenantContext);

export function WorkspaceLayoutProvider({ children }: { children: React.ReactNode }) {
  const [tenantId, setTenantId] = useState("tenant-spbe");
  const [isDarkMode, setIsDarkMode] = useState(true);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);

  // Mapping tenant codes to names
  const tenantName = tenantId === "tenant-spbe" ? "SPBE Pemerintah RI" : "Kementerian Keuangan";
  const tenantDomainLabel = tenantId === "tenant-spbe" ? "tenant-spbe" : "tenant-kemenkeu";

  React.useEffect(() => {
    const root = document.documentElement;
    const savedTheme = localStorage.getItem("vg-theme");
    const nextIsDark = savedTheme ? savedTheme === "dark" : root.classList.contains("dark");
    setIsDarkMode(nextIsDark);
    root.classList.toggle("dark", nextIsDark);
    root.classList.toggle("light", !nextIsDark);

    // Load sidebar collapse preference
    const savedCollapsed = localStorage.getItem("vg-sidebar-collapsed");
    if (savedCollapsed) {
      setIsSidebarCollapsed(savedCollapsed === "true");
    }
  }, []);

  const handleThemeToggle = () => {
    const nextIsDark = !isDarkMode;
    setIsDarkMode(nextIsDark);
    const root = document.documentElement;
    root.classList.toggle("dark", nextIsDark);
    root.classList.toggle("light", !nextIsDark);
    localStorage.setItem("vg-theme", nextIsDark ? "dark" : "light");
  };

  return (
    <TenantContext.Provider value={{ tenantId, setTenantId, tenantName }}>
      <div 
        className="flex h-screen w-screen flex-col overflow-hidden bg-background font-sans text-foreground"
        style={{
          "--sidebar-width": isSidebarCollapsed ? "60px" : "240px",
        } as React.CSSProperties}
      >
        {/* Header */}
        <header className="z-10 flex h-14 shrink-0 select-none items-center justify-between bg-panel px-4 lg:px-5 border-b border-border shadow-sm">
          {/* Left: Brand column + Menu Toggle */}
          <div className="flex shrink-0 items-center gap-2 pr-4">
            <div className="flex h-8 w-8 items-center justify-center rounded-icon bg-primary text-base font-black tracking-tighter text-primary-foreground animate-pulse-slow">
              V
            </div>
            <div className="min-w-0">
              <p className="truncate text-xs font-bold tracking-[0.02em] text-foreground">VARGUARD</p>
              <p className="truncate text-[9px] font-medium tracking-wider text-muted-foreground">METADATA HUB</p>
            </div>
            {/* Sidebar toggle button immediately to the right of the brand logo */}
            <button
              onClick={() => {
                const nextCollapsed = !isSidebarCollapsed;
                setIsSidebarCollapsed(nextCollapsed);
                localStorage.setItem("vg-sidebar-collapsed", String(nextCollapsed));
              }}
              className="ml-3 p-1.5 rounded-control text-muted-foreground hover:bg-muted hover:text-foreground transition-all flex items-center justify-center border border-transparent hover:border-border"
              title={isSidebarCollapsed ? "Lebarkan Sidebar" : "Ciutkan Sidebar"}
            >
              <Menu className="w-4 h-4" />
            </button>
          </div>

          {/* Middle: centered search */}
          <div className="flex flex-1 justify-center px-4 max-w-[32rem] mx-auto">
            <div className="relative w-full">
              <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
              <input
                type="text"
                placeholder={`Search metadata untuk ${tenantName}...`}
                className="h-8 w-full rounded-control border border-input bg-surface py-1.5 pl-8.5 pr-3 text-xs text-foreground placeholder:text-muted-foreground transition-colors focus:outline-none focus:ring-1 focus:ring-ring focus:bg-panel"
              />
            </div>
          </div>

          {/* Right: utility buttons + profile */}
          <div className="ml-4 flex shrink-0 items-center gap-2 lg:gap-3">
            <div className="flex items-center gap-1.5">
              <button
                className="rounded-icon border border-transparent p-1.5 text-muted-foreground transition-all hover:bg-muted hover:text-foreground"
                title={isDarkMode ? "Switch to Light Mode" : "Switch to Dark Mode"}
                onClick={handleThemeToggle}
              >
                {isDarkMode ? <Sun className="w-4 h-4" /> : <Moon className="w-4 h-4" />}
              </button>
              <button className="rounded-icon border border-transparent p-1.5 text-muted-foreground transition-all hover:bg-muted hover:text-foreground" title="Notification Log">
                <Bell className="w-4 h-4" />
              </button>
              <button className="rounded-icon border border-transparent p-1.5 text-muted-foreground transition-all hover:bg-muted hover:text-foreground" title="Docs & Help">
                <HelpCircle className="w-4 h-4" />
              </button>
            </div>

            <details className="group relative">
              <summary className="flex list-none cursor-pointer items-center gap-1 rounded-control p-0.5 text-muted-foreground transition-colors hover:bg-muted hover:text-foreground">
                <div className="flex h-8 w-8 items-center justify-center rounded-full bg-primary/25 font-bold text-xs text-primary">
                  AH
                </div>
                <ChevronsUpDown className="h-3.5 w-3.5" />
              </summary>
              <div className="absolute right-0 top-10 z-20 w-60 rounded-panel border border-border bg-card p-3 shadow-card">
                <div className="space-y-2 text-xs">
                  <div className="flex items-center gap-2 text-foreground">
                    <UserRound className="h-3.5 w-3.5 text-muted-foreground" />
                    <span className="font-semibold">Admin Hub</span>
                  </div>
                  <div className="mt-1.5 rounded-control border border-border bg-surface p-2">
                    <div className="flex items-center gap-2 text-muted-foreground">
                      <Building2 className="h-3.5 w-3.5" />
                      <span className="truncate">{tenantName}</span>
                    </div>
                    <div className="mt-1 flex items-center justify-between font-mono text-[10px] text-muted-foreground">
                      <span>{tenantDomainLabel}</span>
                      <span className="ui-pill">
                        PROD
                      </span>
                    </div>
                  </div>
                </div>
              </div>
            </details>
          </div>
        </header>

        <div className="flex min-h-0 flex-1 overflow-hidden">
          {/* Navigation Sidebar (Vertical at Left Side) */}
          <NavSidebar isCollapsed={isSidebarCollapsed} />

          {/* Main Content Area */}
          <div className="flex h-full min-w-0 flex-1 flex-col overflow-hidden">
            {/* Sub-Page Content Container */}
            <main className="flex-1 overflow-y-auto bg-background p-4 lg:p-5 xl:p-6 2xl:p-8">
              <div className="mx-auto w-full max-w-[1280px] space-y-6 xl:max-w-[1440px] 2xl:max-w-[1800px]">
                {children}
              </div>
            </main>
          </div>
        </div>
      </div>
    </TenantContext.Provider>
  );
}

"use client";

import * as React from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import {
  LayoutDashboard,
  Database,
  LineChart,
  TableProperties,
  GitBranch,
  Network,
  ShieldCheck,
  GitMerge,
  Settings,
  Grid2X2,
  Workflow
} from "lucide-react";
import { cn } from "@/shared/design-system/utils/cn";

export interface NavSidebarProps {
  isCollapsed: boolean;
}

export function NavSidebar({ isCollapsed }: NavSidebarProps) {
  const pathname = usePathname();

  const mainMenuItem = { name: "Dashboard", href: "/dashboard", icon: LayoutDashboard };
  const menuGroups = [
    {
      label: "Metadata Authoring",
      items: [
        { name: "Dataset Registry", href: "/datasets", icon: Database },
        { name: "Variable Registry", href: "/variables", icon: TableProperties },
        { name: "Classifications", href: "/classifications", icon: Grid2X2 },
        { name: "Indicator Registry", href: "/indicators", icon: LineChart }
      ]
    },
    {
      label: "Data Stewardship",
      items: [
        { name: "Lightweight MDM", href: "/mdm", icon: GitMerge },
        { name: "Metadata Quality", href: "/quality", icon: ShieldCheck },
        { name: "Lineage Graph", href: "/lineage", icon: GitBranch }
      ]
    },
    {
      label: "Control & Compliance",
      items: [{ name: "Governance Approval", href: "/governance", icon: Workflow }]
    },
    {
      label: "Platform & Admin",
      items: [
        { name: "Integrations & API", href: "/integrations", icon: Network },
        { name: "System Settings", href: "/settings", icon: Settings }
      ]
    }
  ];

  const renderNavItem = (item: { name: string; href: string; icon: React.ComponentType<{ className?: string }> }) => {
    const isActive = pathname.startsWith(item.href);
    const Icon = item.icon;
    return (
      <Link
        key={item.href}
        href={item.href}
        className={cn(
          "group flex items-center gap-3 rounded-control px-3 py-2.5 text-xs font-medium transition-all",
          isActive
            ? "bg-primary font-semibold text-primary-foreground shadow-sm shadow-primary/10"
            : "text-muted-foreground hover:bg-muted hover:text-foreground",
          isCollapsed && "justify-center px-2"
        )}
        title={isCollapsed ? item.name : undefined}
      >
        <Icon
          className={cn(
            "h-4 w-4 transition-transform group-hover:scale-105 shrink-0",
            isActive ? "text-primary-foreground" : "text-muted-foreground group-hover:text-foreground"
          )}
        />
        {!isCollapsed && <span className="truncate">{item.name}</span>}
      </Link>
    );
  };

  return (
    <aside className="shell-sidebar-width relative flex h-full shrink-0 select-none flex-col bg-panel border-r border-border text-foreground transition-all">
      {/* Navigation Menu */}
      <nav className="flex-1 space-y-4 overflow-y-auto px-3 py-4">
        <div className="space-y-1">
          {renderNavItem(mainMenuItem)}
        </div>

        {menuGroups.map((group) => (
          <div key={group.label} className="space-y-1">
            {!isCollapsed ? (
              <p className="px-3 pb-1 text-[10px] font-semibold uppercase tracking-wider text-muted-foreground truncate">
                {group.label}
              </p>
            ) : (
              <div className="h-px bg-border my-2 mx-1" />
            )}
            {group.items.map((item) => renderNavItem(item))}
          </div>
        ))}
      </nav>
    </aside>
  );
}
